@page "/category/{CategoryName}"
@using RecipeSharing.Models

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Any())
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category.</p>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeStore.Recipes
            .Where(r => r.Category.Equals(CategoryName, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }
}

@page "/recipe/{Id:int}"
@using RecipeSharing.Models

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <p class="text-muted">Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3 class="mt-4">Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.')
                text = text[3..];
            <li>@text</li>
        }
    </ol>

    <h3 class="mt-4">Rate This Recipe</h3>
    <StarRating RecipeId="recipe.Id" />
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeStore.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating" aria-label="Rate this recipe">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "selected" : "")"
              @onclick="() => SetRating(star)"
              role="button"
              aria-label="@star stars">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (currentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @currentRating/5</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int currentRating;

    private void SetRating(int rating)
    {
        currentRating = rating;
    }
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star-rating .star:hover,
.star-rating .star.selected {
    color: #ffc107;
}

@page "/submit"
@using RecipeSharing.Models
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "@model.Title" has been submitted.
    </div>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeStore.Categories)
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="4" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="6" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmitModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        RecipeStore.Recipes.Add(new Recipe
        {
            Id = RecipeStore.Recipes.Max(r => r.Id) + 1,
            Title = model.Title,
            Category = model.Category,
            Ingredients = model.Ingredients,
            Steps = model.Steps
        });
        submitted = true;
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeSharing.Models;

public class RecipeSubmitModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3)]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please list the ingredients.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please describe the steps.")]
    public string Steps { get; set; } = string.Empty;
}

